class Solution {
    public int countVowelPermutation(int n) {
        int mod = 1000000007;
        long a = 1, e = 1, i = 1, o = 1, u = 1;
        if (n == 1) return 5;
        for (int step = 2; step <= n; step++) {
            long newA = (e + i + u) % mod;
            long newE = (a + i) % mod;
            long newI = (e + o) % mod;
            long newO = i % mod;
            long newU = (i + o) % mod;
            a = newA;
            e = newE;
            i = newI;
            o = newO;
            u = newU;
        }
        return (int) ((a + e + i + o + u) % mod);
    }
}

